<script>
let value=$state(""),query=$state(''),open=$state(false),message=$state('Ready'),page=$state(1);let range=['',''],start=$state(range[0]),end=$state(range[1]);const matches=x=>x.toLowerCase().includes(query.toLowerCase());function choose(x){value=x;query=x;open=false}function chooseKey(e,x){if(e.key==='Enter'||e.key===' '){e.preventDefault();choose(x)}}function key(e){if(e.key==='Escape')open=false;else if(e.key==='ArrowDown'||e.key==='ArrowUp'){e.preventDefault();open=true}}
</script>
<main class="family"><h1>Autocomplete</h1><section><label for="search">Fruit</label><input id="search" role="combobox" aria-autocomplete="list" aria-controls="fruit-list" placeholder="Search fruit" bind:value={query} aria-expanded={open} onfocus={()=>open=true} onkeydown={key}>{#if open}<ul id="fruit-list" role="listbox">{#if matches("Apple")}<li role="option" tabindex="-1" aria-selected={value==="Apple"} onclick={()=>choose("Apple")} onkeydown={(event)=>chooseKey(event,"Apple")}>Apple</li>{/if}{#if matches("Banana")}<li role="option" tabindex="-1" aria-selected={value==="Banana"} onclick={()=>choose("Banana")} onkeydown={(event)=>chooseKey(event,"Banana")}>Banana</li>{/if}{#if matches("Cherry")}<li role="option" tabindex="-1" aria-selected={value==="Cherry"} onclick={()=>choose("Cherry")} onkeydown={(event)=>chooseKey(event,"Cherry")}>Cherry</li>{/if}</ul>{/if}</section></main>
